#include <bits/stdc++.h>
using namespace std;

const int N=5003;

int n,m,c[N],p[N],f[N][N],dfn[N],w[N],siz[N],num;
vector<int> g[N];

void dfs(int x){
    dfn[x]=++num,w[num]=x;
    siz[x]=1;
    for(int y:g[x]){
        dfs(y);
        siz[x]+=siz[y];
    }
}

int main(){
    scanf("%d%d",&n,&m);
    for(int i=2,fa;i<=n;i++){
        scanf("%d",&fa);
        g[fa].push_back(i);
    }
    for(int i=1;i<=n;i++)
        scanf("%d",&p[i]);
    for(int i=1;i<=n;i++)
        scanf("%d",&c[i]);
    dfs(1);
    memset(f,0xcf,sizeof(f));
    for(int j=0;j<=m;j++)
    	f[1][j]=0;
    for(int i=1;i<=n;i++){
        int x=w[i];
        for(int j=0;j<=m;j++){
            if(j+1<=m)
                f[i+1][j+1]=max(f[i+1][j+1],f[i][j]);
            if(j+c[x]<=m)
                f[i+1][j+c[x]]=max(f[i+1][j+c[x]],f[i][j]+p[x]);
            f[i+siz[x]][j]=max(f[i+siz[x]][j],f[i][j]);
            //printf("%d ",f[i][j]);
        }
        //puts("");
    }
    printf("%d",f[n+1][m]);
    return 0;
}
